function openDB(callback) {
  const request = indexedDB.open("tpt-db", 1);
  request.onupgradeneeded = () => {
    const db = request.result;
    if (!db.objectStoreNames.contains("recordings")) {
      db.createObjectStore("recordings");
    }
    if (!db.objectStoreNames.contains("states")) {
      db.createObjectStore("states");
    }
  };
  request.onsuccess = () => {
    const db = request.result;
    // 如果舊版資料庫缺少 recordings，就刪掉重建
    if (!db.objectStoreNames.contains("recordings")) {
      db.close();
      const del = indexedDB.deleteDatabase("tpt-db");
      del.onsuccess = () => openDB(callback);
      return;
    }
    callback(db);
  };
}
function loadRecording(fileidx, callback) {
  const request = indexedDB.open("tpt-db", 1);
  request.onsuccess = () => {
    const db = request.result;
    const tx = db.transaction("recordings", "readonly");
    const store = tx.objectStore("recordings");
    const getReq = store.get(String(fileidx));
    getReq.onsuccess = () => {
      callback(getReq.result || null);
    };
  };
}
