          <img src={displayImage} style={{ position: "absolute", top: "10px", right: "10px", width: "15vw", zIndex: 1000 }} />
          <button style={{ position: "absolute", left: "0px"}} onClick={() => handlerestart(setCleared, setFileidx, setshowed_posterior)}> restart </button>
          <button onClick={() => handlenextwav(setFileidx, Fileidx, setwavePlayer_url, setshowed_text, setshowed_pinyin, setshowed_posterior)}> Next </button>

          < WavePlayer_example url={wavePlayer_url} EG={exp_group} />
          <button onClick={() => recompute(boundaries)}> recompute </button>
          < Retrecordhtmls key={Fileidx} tag="exp" Fileidx={Fileidx} exp_group={exp_group} profile={participant_id+"_"+age+"_"+gender+"_"+mother_language+"_"+study_years+"_"+tocfl} setshowed_posterior={setshowed_posterior} setboundaries={setboundaries}/>
        </>
      )}

      {!cleared && (
        <>
          <div>
            <h1>Welcome</h1>
            < Welcomeinterface setPI={setParticipant_Id} setA={setAge} setG={setGender} setM={setMother_Language} setS={setStudy_Years} setT={setTocfl} setEG={setExpGroup} />
            < ConfirmSubjectInfo PI={participant_id} A={age} G={gender} M={mother_language} S={study_years} T={tocfl} EG={exp_group} setCleared={setCleared} setDisplayImage={setDisplayImage} setwavePlayer_url={setwavePlayer_url} setshowed_text={setshowed_text} Fileidx={Fileidx} setshowed_pinyin={setshowed_pinyin}/>

          </div>
          <h1>Nice react audio player with Wavesurfer.js + Timeline </h1>
          < WavePlayer url="./exp_data/mono_example_fan1.wav" />
          < WavePlayer url="./exp_data/mono_example_wu2.wav" />
          < WavePlayer url="./exp_data/mono_example_kou3.wav" />
          < WavePlayer url="./exp_data/mono_example_chu4.wav" />
          < WavePlayer url="./exp_data/sentence_example_1.wav" />
          < Retrecordhtmls tag="demo" Fileidx="" exp_group="" profile=""/>
        </>
      )
      }
    </div>
  )
}
